function clone(v){return JSON.parse(JSON.stringify(v));}
function clamp(n,min,max){return Math.max(min,Math.min(max,n));}
function getByPath(obj,path){return path.split('.').reduce((acc,key)=>acc?.[key],obj);}
function setByPath(obj,path,value){const parts=path.split('.');let cur=obj;for(let i=0;i<parts.length-1;i++)cur=cur[parts[i]];cur[parts[parts.length-1]]=value;}
function escapeHtml(str){return String(str).replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;');}
function deepMerge(base,override){if(Array.isArray(base)||Array.isArray(override)) return override ?? base; if(typeof base!=='object'||base===null) return override ?? base; const out={...base}; for(const key of Object.keys(override||{})){out[key]=key in base? deepMerge(base[key],override[key]) : override[key];} return out;}
function loadState(){try{const raw=localStorage.getItem(STORAGE_KEY); if(!raw) return clone(DEFAULT_STATE); return deepMerge(clone(DEFAULT_STATE), JSON.parse(raw));}catch(err){return clone(DEFAULT_STATE);}}
let state = loadState(); let lastSavedAt='';
function derived(){const violBonus = state.resources.holdingViol && state.attunement.viol; return {ac: state.resources.shieldActive ? DATA.combat.shieldAC : DATA.combat.baseAC, spellDc: violBonus ? DATA.spellcasting.saveDCWithViol : DATA.spellcasting.saveDCBase, spellAtk: violBonus ? DATA.spellcasting.attackWithViol : DATA.spellcasting.attackBase, hpPct: state.hp.max > 0 ? Math.max(0, Math.min(100, Math.round((state.hp.current / state.hp.max) * 100))) : 0, attunedCount: Object.values(state.attunement).filter(Boolean).length};}
function saveState(){localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); lastSavedAt = new Date().toLocaleTimeString([], {hour:'numeric', minute:'2-digit'});}
function counterCard(title,path,max,meta){const value=Number(getByPath(state,path) ?? 0); const cap=typeof max==='string'? Number(getByPath(state,max) ?? 0): Number(max); const depleted=value<=0; return `<div class="resource-card ${depleted?'depleted':'available'}"><div class="resource-top"><div><div class="resource-name">${escapeHtml(title)}</div><div class="resource-meta">${escapeHtml(meta)}</div></div><div class="small"><strong>${value}</strong> / ${cap}</div></div><div class="stepper"><button data-action="dec" data-path="${path}">−</button><div class="stepper-value">${value}</div><button data-action="inc" data-path="${path}" data-max="${cap}">+</button></div></div>`;}
function boolCard(title,path,meta,onLabel='Available',offLabel='Used',style='on'){const value=!!getByPath(state,path); const klass=value ? (style==='neutral' ? 'neutral-on' : 'on') : 'off'; return `<div class="resource-card ${value?'available':'depleted'}"><div class="resource-top"><div><div class="resource-name">${escapeHtml(title)}</div><div class="resource-meta">${escapeHtml(meta)}</div></div></div><button class="toggle-btn ${klass}" data-action="toggle" data-path="${path}">${value ? onLabel : offLabel}</button></div>`;}
function activeSpellFilterCount(){const f=state.ui.spellFilters||{}; return (f.timing?1:0) + (f.concentration?1:0) + (f.ritual?1:0);}
function clearSpellFilters(){state.ui.spellFilters={timing:'', concentration:false, ritual:false};}
function getSpellMeta(spell){const raw=SPELL_META[spell.name]||{}; const tags=spell.tags||[]; return {timing: raw.timing || 'action', concentration: !!raw.concentration, ritual: !!raw.ritual || tags.includes('Ritual'), range: raw.range || '—', duration: raw.duration || '—', components: raw.components || '—'};}
function spellKey(spell){return spell.id || spell.name;}
function isSpellExpanded(spell){return !!(state.ui.expandedSpells && state.ui.expandedSpells[spellKey(spell)]);}
function spellMatchesFilters(spell){const filters=state.ui.spellFilters||{}; const meta=getSpellMeta(spell); if(filters.timing && meta.timing!==filters.timing) return false; if(filters.concentration && !meta.concentration) return false; if(filters.ritual && !meta.ritual) return false; return true;}
function renderSpellFilterBar(){const filters=state.ui.spellFilters||{}; const timingButton=(value,label)=>`<button class="spell-filter-btn ${filters.timing===value?'active':''}" data-action="toggleSpellFilter" data-filter="timing" data-value="${value}">${label}</button>`; const toggleButton=(key,label)=>`<button class="spell-filter-btn ${filters[key]?'active':''}" data-action="toggleSpellFilter" data-filter="${key}" data-value="${filters[key]?'off':'on'}">${label}</button>`; return `<div class="spell-filter-wrap"><div class="spell-filter-bar">${timingButton('action','Action')}${timingButton('bonus','Bonus Action')}${timingButton('reaction','Reaction')}${toggleButton('concentration','Concentration')}${toggleButton('ritual','Ritual')}${activeSpellFilterCount()?'<button class="spell-filter-btn" data-action="clearSpellFilters">Clear filters</button>':''}</div><div class="spell-filter-note">Filter by casting time and maintenance. Click a spell name to expand its details. Spell detail tags use 5etools metadata and prefer newer reprints when available; source/category tags remain unchanged.</div></div>`;}
function renderSpellSection(groups){const blocks=groups.map(([label,spells])=>{const filtered=spells.filter(spellMatchesFilters); if(!filtered.length) return ''; return `<div class="spell-group"><h3 class="spell-level-title">${escapeHtml(label)}</h3><div class="spell-card-grid">${filtered.map(spell=>spellCard(spell)).join('')}</div></div>`;}).filter(Boolean).join(''); return blocks || `<div class="empty-state">No spells in this section match the active filters.</div>`;}
function renderSpiritResult(){if(!state.lastSpiritRoll) return `<div class="footer-note">Spirits from Beyond currently uses only results 1–10 at Bard 11.</div>`; const spirit = DATA.spirits.find(s=>s.roll===state.lastSpiritRoll); if(!spirit) return ''; return `<div class="spirits-result"><strong>Spirit result ${spirit.roll} — ${escapeHtml(spirit.name)}</strong><div class="small" style="margin-top:6px;line-height:1.45;">${escapeHtml(spirit.effect)}</div></div>`;}
function renderHeader(){const d=derived(); return `<section class="hero"><div class="hero-top"><div class="title-wrap"><h1>${escapeHtml(DATA.identity.name)}</h1><p class="subtitle">${escapeHtml(DATA.identity.classLevel)} • ${escapeHtml(DATA.identity.subclass)} • ${escapeHtml(DATA.identity.species)} • ${escapeHtml(DATA.identity.background)}</p><div class="chip-row"><span class="chip accent">Faction: ${escapeHtml(DATA.identity.faction)}</span><span class="chip">PB ${escapeHtml(DATA.identity.pb)}</span><span class="chip">Speed ${escapeHtml(DATA.identity.speed)}</span><span class="chip">Languages: ${escapeHtml(DATA.identity.languages.join(', '))}</span><span class="chip">Attunement ${d.attunedCount}/3</span></div></div><div class="status-banner"><button class="toggle-btn ${state.resources.concentration?'on':'off'}" data-action="toggle" data-path="resources.concentration">${state.resources.concentration?'Concentrating':'Not concentrating'}</button><button class="toggle-btn ${state.resources.reactionUsed?'off':'neutral-on'}" data-action="toggle" data-path="resources.reactionUsed">${state.resources.reactionUsed?'Reaction spent':'Reaction ready'}</button><button class="toggle-btn ${state.resources.shieldActive?'on':'off'}" data-action="toggleShield">${state.resources.shieldActive?'Shield active (+5 AC)':'Shield inactive'}</button><button class="toggle-btn ${state.resources.holdingViol?'neutral-on':'off'}" data-action="toggle" data-path="resources.holdingViol">${state.resources.holdingViol?'Holding Elegist’s Viol':'Viol not in hand'}</button><span class="saved-pill">Saved locally${lastSavedAt?` • ${lastSavedAt}`:''}</span></div></div><div class="hero-metrics"><div class="metric"><div class="metric-label">Armor Class</div><div class="metric-value">${d.ac}</div><div class="metric-sub">Base 14. Shield state shows 19 against a triggering attack.</div></div><div class="metric"><div class="metric-label">Hit Points</div><div class="metric-value">${state.hp.current} / ${state.hp.max}</div><div class="metric-sub">Temp HP ${state.hp.temp} • ${d.hpPct}%</div></div><div class="metric"><div class="metric-label">Spell Save DC</div><div class="metric-value">${d.spellDc}</div><div class="metric-sub">Base 17 • 18 while holding the attuned viol</div></div><div class="metric"><div class="metric-label">Spell Attack</div><div class="metric-value">+${d.spellAtk}</div><div class="metric-sub">Base +9 • +10 while holding the attuned viol</div></div><div class="metric"><div class="metric-label">Bardic Inspiration</div><div class="metric-value">${state.resources.bardicInspiration} / 5</div><div class="metric-sub">d10 • Short or Long Rest</div></div><div class="metric"><div class="metric-label">Passives</div><div class="metric-value">18 / 18 / 18</div><div class="metric-sub">Perception • Investigation • Insight</div></div></div></section>`;}
function renderStatusBar(){const d=derived(); return `<div class="status-strip"><div class="status-tile"><div class="status-copy"><div class="status-label">HP</div><div class="status-value">${state.hp.current} / ${state.hp.max}</div></div><div class="status-note">${d.hpPct}%</div></div><div class="status-tile"><div class="status-copy"><div class="status-label">Temp HP</div><div class="status-value">${state.hp.temp}</div></div><div class="status-note">Buffer</div></div><div class="status-tile"><div class="status-copy"><div class="status-label">AC</div><div class="status-value">${d.ac}</div></div><div class="status-note">${state.resources.shieldActive?'Shield':'Base'}</div></div><div class="status-tile"><div class="status-copy"><div class="status-label">Spell DC</div><div class="status-value">${d.spellDc}</div></div><div class="status-note">Save</div></div><div class="status-tile"><div class="status-copy"><div class="status-label">Spell Atk</div><div class="status-value">+${d.spellAtk}</div></div><div class="status-note">To hit</div></div><div class="status-tile"><div class="status-copy"><div class="status-label">Bardic Insp.</div><div class="status-value">${state.resources.bardicInspiration} / 5</div></div><div class="stepper"><button data-action="dec" data-path="resources.bardicInspiration">−</button><button data-action="inc" data-path="resources.bardicInspiration" data-max="5">+</button></div></div><div class="status-tile action-tile"><div style="width:100%;"><div class="status-label">Concentration</div><button class="toggle-btn ${state.resources.concentration?'on':'off'}" data-action="toggle" data-path="resources.concentration">${state.resources.concentration?'Active':'Off'}</button></div></div><div class="status-tile action-tile"><div style="width:100%;"><div class="status-label">Reaction</div><button class="toggle-btn ${state.resources.reactionUsed?'off':'neutral-on'}" data-action="toggle" data-path="resources.reactionUsed">${state.resources.reactionUsed?'Spent':'Ready'}</button></div></div></div>`;}
function renderTabs(){const tabs=[['overview','Overview'],['abilities','Abilities / saves / skills'],['combat','Combat'],['features','Features'],['spells','Spells'],['inventory','Inventory / items'],['notes','Notes'],['rest','Rest / resource reset']]; return `<div class="sticky-shell"><nav class="tabs">${tabs.map(([id,label])=>`<button class="tab-btn ${state.ui.activeTab===id?'active':''}" data-action="tab" data-tab="${id}">${escapeHtml(label)}</button>`).join('')}</nav>${renderStatusBar()}</div>`;}
function renderOverview(){return `<section class="tab-panel ${state.ui.activeTab==='overview'?'active':''}" data-tab="overview"><div class="section-grid"><div class="card span-7"><h2>Character profile</h2><p>${escapeHtml(DATA.identity.summary)}</p><div class="summary-grid"><div class="item-card"><h3>Core data</h3><div class="kv-grid"><div class="kv"><div class="kv-label">Alignment</div><div class="kv-value">${escapeHtml(DATA.identity.alignment)}</div></div><div class="kv"><div class="kv-label">XP</div><div class="kv-value">${escapeHtml(DATA.identity.xp)}</div></div><div class="kv"><div class="kv-label">Size</div><div class="kv-value">${escapeHtml(DATA.identity.size)}</div></div><div class="kv"><div class="kv-label">Role</div><div class="kv-value">${escapeHtml(DATA.identity.role.join(', '))}</div></div></div></div><div class="item-card"><h3>Table-facing vibe</h3><p class="small">${escapeHtml(DATA.identity.vibe)}</p></div></div></div><div class="card span-5"><h2>Current combat state</h2><div class="resource-grid">${counterCard('Bardic Inspiration','resources.bardicInspiration',5,'d10 • Short or Long Rest')}${counterCard('Blessing of the Raven Queen','resources.blessing',4,'Bonus Action teleport • Long Rest')}${counterCard('Hit Dice','hitDiceRemaining',11,'11d8 remaining')}</div><div class="footer-note">Shield, Spirit Guardians free cast, Spirit Guardians Half Cover, Elegist’s Viol recovery, and Fochlucan Bandore item casts are tracked in Combat, Spells, and Inventory.</div></div><div class="card span-6"><h2>Personality</h2><ul class="list-clean">${DATA.identity.personality.map(line=>`<li>${escapeHtml(line)}</li>`).join('')}</ul></div><div class="card span-6"><h2>Backstory</h2><p>${escapeHtml(DATA.identity.backstory)}</p></div><div class="card span-12"><div style="display:flex;justify-content:space-between;gap:12px;align-items:center;flex-wrap:wrap;"><h2>Quick tactical notes</h2><button class="spirit-btn" data-action="rollSpirit">Draw spirit (d10)</button></div><ul class="list-clean">${DATA.tacticalNotes.map(line=>`<li>${escapeHtml(line)}</li>`).join('')}</ul>${renderSpiritResult()}</div></div></section>`;}
function renderAbilities(){return `<section class="tab-panel ${state.ui.activeTab==='abilities'?'active':''}" data-tab="abilities"><div class="section-grid"><div class="card span-12"><h2>Ability scores</h2><div class="ability-grid">${DATA.abilities.map(a=>`<div class="ability-card"><div class="abbr">${escapeHtml(a.abbr)}</div><div class="score">${a.score}</div><div>${escapeHtml(a.name)}</div><div class="mod">${escapeHtml(a.mod)}</div></div>`).join('')}</div></div><div class="card span-5"><h2>Saving throws</h2><table><thead><tr><th>Save</th><th>Bonus</th><th>Notes</th></tr></thead><tbody>${DATA.saves.map(row=>`<tr><td>${escapeHtml(row.name)}</td><td><strong>${escapeHtml(row.bonus)}</strong></td><td>${escapeHtml(row.notes)}</td></tr>`).join('')}</tbody></table></div><div class="card span-7"><h2>Skill bonuses</h2><table><thead><tr><th>Skill</th><th>Bonus</th><th>Notes</th></tr></thead><tbody>${DATA.skills.map(([skill,bonus,notes])=>`<tr><td>${escapeHtml(skill)}</td><td><strong>${escapeHtml(bonus)}</strong></td><td>${escapeHtml(notes)}</td></tr>`).join('')}</tbody></table></div><div class="card span-12"><h2>Proficiencies</h2><div class="summary-grid">${Object.entries(DATA.proficiencies).map(([heading,values])=>`<div class="item-card"><h3>${escapeHtml(heading)}</h3><ul class="list-clean">${values.map(v=>`<li>${escapeHtml(v)}</li>`).join('')}</ul></div>`).join('')}</div></div></div></section>`;}
function renderCombat(){return `<section class="tab-panel ${state.ui.activeTab==='combat'?'active':''}" data-tab="combat"><div class="section-grid"><div class="card span-6"><h2>Hit point tracking</h2><div class="input-row"><div class="field"><label for="hp-current">Current HP</label><input id="hp-current" type="number" min="0" value="${state.hp.current}" data-action="number" data-path="hp.current"></div><div class="field"><label for="hp-max">Max HP</label><input id="hp-max" type="number" min="1" value="${state.hp.max}" data-action="number" data-path="hp.max"></div><div class="field"><label for="hp-temp">Temp HP</label><input id="hp-temp" type="number" min="0" value="${state.hp.temp}" data-action="number" data-path="hp.temp"></div></div><div class="footer-note">AC is 14 in studded leather, or 19 against a triggering attack while Shield is active.</div></div><div class="card span-6"><h2>Combat state</h2><div class="inline-controls" style="margin-bottom:10px;"><button class="toggle-btn ${state.resources.concentration?'on':'off'}" data-action="toggle" data-path="resources.concentration">${state.resources.concentration?'Concentrating':'Not concentrating'}</button><button class="toggle-btn ${state.resources.reactionUsed?'off':'neutral-on'}" data-action="toggle" data-path="resources.reactionUsed">${state.resources.reactionUsed?'Reaction spent':'Reaction ready'}</button><button class="toggle-btn ${state.resources.shieldActive?'on':'off'}" data-action="toggleShield">${state.resources.shieldActive?'Shield active':'Shield inactive'}</button></div><div class="death-row"><div class="death-track"><strong>Successes</strong>${[0,1,2].map(i=>`<label><input type="checkbox" data-action="checkbox" data-path="deathSaves.successes.${i}" ${state.deathSaves.successes[i]?'checked':''}></label>`).join('')}</div><div class="death-track"><strong>Failures</strong>${[0,1,2].map(i=>`<label><input type="checkbox" data-action="checkbox" data-path="deathSaves.failures.${i}" ${state.deathSaves.failures[i]?'checked':''}></label>`).join('')}</div></div></div><div class="card span-12"><h2>Resources</h2><div class="resource-grid">${counterCard('Bardic Inspiration','resources.bardicInspiration',5,'Bonus Action • d10 • Short or Long Rest')}${counterCard('Blessing of the Raven Queen','resources.blessing',4,'Bonus Action teleport • Long Rest')}${counterCard('Hit Dice','hitDiceRemaining',11,'11d8 • spend manually on Short Rest')}${boolCard('Shield free cast','resources.shieldFree','Magic Initiate • free cast once per Long Rest')}${boolCard('Spirit Guardians free cast','resources.spiritGuardiansFree','Subclass • free cast once per Long Rest')}${boolCard('Spirit Guardians Half Cover','resources.spiritGuardiansCover','Protective modification • Short or Long Rest')}</div></div><div class="card span-12"><h2>Attacks</h2><table><thead><tr><th>Attack</th><th>To hit / DC</th><th>Damage</th><th>Notes</th></tr></thead><tbody>${DATA.attacks.map(([name,hit,damage,notes])=>`<tr><td>${escapeHtml(name)}</td><td><strong>${escapeHtml(hit)}</strong></td><td>${escapeHtml(damage)}</td><td>${escapeHtml(notes)}</td></tr>`).join('')}</tbody></table></div><div class="card span-12"><h2>Combat scratch notes</h2><div class="field"><label for="combat-notes">Runtime combat notes</label><textarea id="combat-notes" data-action="textarea" data-path="notes.combat">${escapeHtml(state.notes.combat)}</textarea></div></div></div></section>`;}
function renderFeatures(){return `<section class="tab-panel ${state.ui.activeTab==='features'?'active':''}" data-tab="features"><div class="section-grid">${Object.entries(DATA.features).map(([group,items],idx)=>`<div class="card span-6"><h2>${escapeHtml(group)}</h2>${items.map((item,itemIdx)=>`<details class="feature-block" ${(idx===0 && itemIdx===0)?'open':''}><summary>${escapeHtml(item.title)}</summary><ul class="list-clean" style="margin-top:10px;">${item.lines.map(line=>`<li>${escapeHtml(line)}</li>`).join('')}</ul></details>`).join('')}</div>`).join('')}<div class="card span-12"><div style="display:flex;justify-content:space-between;gap:12px;align-items:center;flex-wrap:wrap;"><h2>Spirits from Beyond table at Bard 11 (d10 only)</h2><button class="spirit-btn" data-action="rollSpirit">Draw spirit (d10)</button></div><table><thead><tr><th>Roll</th><th>Spirit</th><th>Effect</th></tr></thead><tbody>${DATA.spirits.map(s=>`<tr><td><strong>${s.roll}</strong></td><td>${escapeHtml(s.name)}</td><td>${escapeHtml(s.effect)}</td></tr>`).join('')}</tbody></table><div class="footer-note">${escapeHtml(DATA.spiritsNote)}</div>${renderSpiritResult()}</div></div></section>`;}
function spellCard(spell){const meta=getSpellMeta(spell); const timingLabel=meta.timing==='bonus'?'1 Bonus Action':meta.timing==='reaction'?'1 Reaction':'1 Action'; const sourceTags=[...(spell.tags||[])]; const detailTags=[timingLabel, meta.range, meta.duration, `Components: ${meta.components}`, ...(meta.concentration?['Concentration']:[]), ...(meta.ritual?['Ritual']:[])]; const effectTags=[...(meta.damage?[meta.damage]:[]), ...(meta.save?[meta.save]:[])]; const expanded=isSpellExpanded(spell); const key=spellKey(spell); const itemAvailable=spell.id ? !!state.itemUses[spell.id] : null; const cardClasses=['spell-card']; if(expanded) cardClasses.push('expanded'); if(spell.id && !itemAvailable) cardClasses.push('depleted'); return `<div class="${cardClasses.join(' ')}"><button class="spell-row-btn" data-action="toggleSpellExpand" data-key="${escapeHtml(key)}" aria-expanded="${expanded?'true':'false'}"><span class="spell-name-wrap"><span class="spell-chevron">▸</span><span class="spell-name">${escapeHtml(spell.name)}</span></span></button><div class="spell-card-body">${sourceTags.length?`<div class="spell-tags">${sourceTags.map(tag=>`<span class="tag ${/Magical Secrets|Subclass|Magic Initiate/.test(tag)?'special':/Fochlucan|Item cast/.test(tag)?'item':''}">${escapeHtml(tag)}</span>`).join('')}</div>`:''}<div class="spell-detail-row">${detailTags.map(tag=>`<span class="tag meta">${escapeHtml(tag)}</span>`).join('')}</div>${effectTags.length?`<div class="spell-effect-row">${effectTags.map(tag=>`<span class="tag effect">${escapeHtml(tag)}</span>`).join('')}</div>`:''}${spell.id ? `<div class="pill-grid"><button class="use-pill ${itemAvailable?'available':'spent'}" data-action="toggleItemUse" data-key="${spell.id}">${itemAvailable?'Available':'Used'}</button></div>` : ''}</div></div>`;}
function renderSpellSlots(){return Object.entries(DATA.spellSlots).map(([level,max])=>{const current=state.spellSlots[level]; return `<div class="slot-row"><div><strong>${LEVEL_ORDINAL[level]}</strong> level</div><div class="slot-pips">${Array.from({length:max},(_,i)=>`<span class="slot-pip ${i<current?'filled':''}"></span>`).join('')}</div><div class="stepper"><button data-action="dec" data-path="spellSlots.${level}">−</button><div class="stepper-value">${current}</div><button data-action="inc" data-path="spellSlots.${level}" data-max="${max}">+</button></div></div>`;}).join('');}
function renderSpells(){const d=derived(); const totalSpellCount=33; const visibleSpellCount=[...Object.values(DATA.cantrips).flat(), ...Object.values(DATA.preparedSpells).flat(), ...Object.values(DATA.specialSpells).filter(v=>Array.isArray(v)).flat(), ...Object.values(DATA.specialSpells['Item-granted spells']).flat()].filter(spellMatchesFilters).length; return `<section class="tab-panel ${state.ui.activeTab==='spells'?'active':''}" data-tab="spells"><div class="section-grid"><div class="card span-12"><h2>Spellcasting</h2><div class="spell-stat-row"><div class="metric"><div class="metric-label">Spell Save DC</div><div class="metric-value">${d.spellDc}</div><div class="metric-sub">17 base • 18 while holding the attuned Elegist’s Viol +1</div></div><div class="metric"><div class="metric-label">Spell Attack Bonus</div><div class="metric-value">+${d.spellAtk}</div><div class="metric-sub">+9 base • +10 while holding the attuned Elegist’s Viol +1</div></div><div class="metric"><div class="metric-label">Prepared Bard spells</div><div class="metric-value">16</div><div class="metric-sub">Spirit Guardians does not count against this total</div></div><div class="metric"><div class="metric-label">Focus</div><div class="metric-value" style="font-size:1rem;">${escapeHtml(DATA.spellcasting.ability)}</div><div class="metric-sub">${escapeHtml(DATA.spellcasting.focus)}</div></div></div>${renderSpellFilterBar()}<div class="spell-filter-note">Showing ${visibleSpellCount} of ${totalSpellCount} spells.</div></div><div class="card span-5"><h2>Spell slots</h2>${renderSpellSlots()}</div><div class="card span-7"><h2>Cantrips</h2>${renderSpellSection(Object.entries(DATA.cantrips))}</div><div class="card span-8"><h2>Prepared Bard spells</h2>${renderSpellSection(Object.entries(DATA.preparedSpells))}</div><div class="card span-4"><h2>Always prepared / special source spells</h2>${renderSpellSection(Object.entries(DATA.specialSpells).filter(([k])=>k!=='Item-granted spells'))}<div class="resource-grid" style="margin-top:12px;grid-template-columns:1fr;">${boolCard('Shield free cast','resources.shieldFree','Magic Initiate • also castable with slots')}${boolCard('Spirit Guardians free cast','resources.spiritGuardiansFree','Subclass • does not count against prepared total')}${boolCard('Spirit Guardians Half Cover','resources.spiritGuardiansCover','Protective modification • Short or Long Rest')}</div></div><div class="card span-12"><h2>Item-granted spells (Fochlucan Bandore)</h2><p class="small muted">These are item casts, not prepared Bard spells. The markdown source marks them as 1/dawn. In this sheet, per your instruction, the Long Rest reset refreshes them.</p>${renderSpellSection(Object.entries(DATA.specialSpells['Item-granted spells']))}</div></div></section>`;}
function renderInventory(){return `<section class="tab-panel ${state.ui.activeTab==='inventory'?'active':''}" data-tab="inventory"><div class="section-grid"><div class="card span-5"><h2>Attunement state</h2>${DATA.attunement.map(item=>`<div class="attune-row"><div>${escapeHtml(item.label)}</div><button class="toggle-btn ${state.attunement[item.key]?'on':'off'}" data-action="toggle" data-path="attunement.${item.key}">${state.attunement[item.key]?'Attuned / occupied':'Open / unattuned'}</button></div>`).join('')}<div class="footer-note">The source loadout is two attuned items and one open slot.</div></div><div class="card span-7"><h2>Magic items</h2><div class="summary-grid">${DATA.magicItems.map(item=>`<div class="item-card"><h3>${escapeHtml(item.name)}</h3><p class="muted small">${escapeHtml(item.subtitle)}</p><ul class="list-clean">${item.lines.map(line=>`<li>${escapeHtml(line)}</li>`).join('')}</ul>${item.id==='viol' ? `<div class="pill-grid"><button class="use-pill ${state.resources.violRecover?'available':'spent'}" data-action="toggle" data-path="resources.violRecover">${state.resources.violRecover?'Viol recovery available':'Viol recovery used'}</button></div>` : ''}</div>`).join('')}</div></div><div class="card span-6"><h2>Standard worn / carried gear</h2><ul class="list-clean">${DATA.gear.map(item=>`<li>${escapeHtml(item)}</li>`).join('')}</ul></div><div class="card span-6"><h2>Consumables</h2><div class="consumables-grid">${Object.entries(state.consumables).map(([name,qty])=>counterCard(name,`consumables.${name}`, Number(qty)+99, 'Runtime quantity tracker')).join('')}</div></div><div class="card span-12"><h2>Recommended 500 gp package</h2><table><thead><tr><th>Item</th><th>Qty</th><th>Cost each</th><th>Total</th></tr></thead><tbody>${DATA.purchasePlan.map(([item,qty,each,total])=>`<tr><td>${escapeHtml(String(item))}</td><td>${escapeHtml(String(qty))}</td><td>${escapeHtml(String(each))}</td><td><strong>${escapeHtml(String(total))}</strong></td></tr>`).join('')}</tbody></table><div class="footer-note">${escapeHtml(DATA.remainingCoin)}</div></div></div></section>`;}
function renderNotes(){return `<section class="tab-panel ${state.ui.activeTab==='notes'?'active':''}" data-tab="notes"><div class="section-grid"><div class="card span-6"><h2>Character notes</h2><p>${escapeHtml(DATA.identity.session0)}</p><p class="small muted">${escapeHtml(DATA.identity.vibe)}</p></div><div class="card span-6"><h2>Runtime notes</h2><div class="field"><label for="runtime-notes">Editable play notes</label><textarea id="runtime-notes" data-action="textarea" data-path="notes.runtime">${escapeHtml(state.notes.runtime)}</textarea></div></div><div class="card span-12"><h2>Reference notes from the markdown</h2><ul class="list-clean">${DATA.tacticalNotes.map(line=>`<li>${escapeHtml(line)}</li>`).join('')}</ul></div></div></section>`;}
function renderRest(){return `<section class="tab-panel ${state.ui.activeTab==='rest'?'active':''}" data-tab="rest"><div class="section-grid"><div class="card span-7"><h2>Reset actions</h2><div class="rest-actions"><button class="ghost-btn primary" data-action="shortRest">Short Rest reset</button><button class="ghost-btn warn" data-action="longRest">Long Rest reset</button><button class="ghost-btn danger" data-action="resetAll">Reset all trackers</button></div><div class="summary-grid"><div class="item-card"><h3>Short Rest</h3><ul class="list-clean small"><li>Resets Bardic Inspiration to 5.</li><li>Resets Spirit Guardians Half Cover use.</li><li>Clears reaction used, concentration, and Shield active state.</li><li>Leaves HP, spell slots, Blessing, free casts, item casts, consumables, and hit dice unchanged.</li></ul></div><div class="item-card"><h3>Long Rest</h3><ul class="list-clean small"><li>Restores HP to max and temp HP to 0.</li><li>Resets hit dice to 11, death saves, reaction used, concentration, and Shield active state.</li><li>Resets Bardic Inspiration, Blessing of the Raven Queen, Shield free cast, Spirit Guardians free cast, and Spirit Guardians Half Cover.</li><li>Restores all spell slots, Elegist’s Viol recovery, and all Fochlucan Bandore item-cast trackers.</li></ul></div></div></div><div class="card span-5"><h2>Tracker snapshot</h2><div class="kv-grid"><div class="kv"><div class="kv-label">HP</div><div class="kv-value">${state.hp.current} / ${state.hp.max} (+${state.hp.temp} temp)</div></div><div class="kv"><div class="kv-label">Hit dice</div><div class="kv-value">${state.hitDiceRemaining} / 11</div></div><div class="kv"><div class="kv-label">Bardic Inspiration</div><div class="kv-value">${state.resources.bardicInspiration} / 5</div></div><div class="kv"><div class="kv-label">Blessing uses</div><div class="kv-value">${state.resources.blessing} / 4</div></div><div class="kv"><div class="kv-label">Spell slots</div><div class="kv-value">${Object.entries(state.spellSlots).map(([lvl,v])=>`${lvl}:${v}`).join(' • ')}</div></div><div class="kv"><div class="kv-label">Concentration / reaction</div><div class="kv-value">${state.resources.concentration?'Concentrating':'Clear'} • ${state.resources.reactionUsed?'Reaction spent':'Reaction ready'}</div></div></div><div class="footer-note">Local state is saved automatically in this browser via localStorage.</div></div></div></section>`;}
function renderApp(){saveState(); document.getElementById('app').innerHTML = `${renderHeader()}${renderTabs()}${renderOverview()}${renderAbilities()}${renderCombat()}${renderFeatures()}${renderSpells()}${renderInventory()}${renderNotes()}${renderRest()}`;}
function shortRest(){state.resources.bardicInspiration=5; state.resources.spiritGuardiansCover=true; state.resources.reactionUsed=false; state.resources.concentration=false; state.resources.shieldActive=false;}
function longRest(){state.hp.current=state.hp.max; state.hp.temp=0; state.hitDiceRemaining=11; state.deathSaves.successes=[false,false,false]; state.deathSaves.failures=[false,false,false]; state.resources.bardicInspiration=5; state.resources.blessing=4; state.resources.shieldFree=true; state.resources.spiritGuardiansFree=true; state.resources.spiritGuardiansCover=true; state.resources.violRecover=true; state.resources.reactionUsed=false; state.resources.concentration=false; state.resources.shieldActive=false; state.spellSlots=clone(DATA.spellSlots); Object.keys(state.itemUses).forEach(k=>state.itemUses[k]=true);}
function resetAll(){state=clone(DEFAULT_STATE);}
function handleClick(event){const btn=event.target.closest('[data-action]'); if(!btn) return; const action=btn.dataset.action; if(action==='tab'){state.ui.activeTab=btn.dataset.tab; renderApp(); return;} if(action==='toggleSpellFilter'){const filter=btn.dataset.filter; const value=btn.dataset.value; if(filter==='timing'){state.ui.spellFilters.timing = state.ui.spellFilters.timing===value ? '' : value;} else {state.ui.spellFilters[filter]=!state.ui.spellFilters[filter];} renderApp(); return;} if(action==='clearSpellFilters'){clearSpellFilters(); renderApp(); return;} if(action==='toggleSpellExpand'){state.ui.expandedSpells = state.ui.expandedSpells || {}; const key=btn.dataset.key; state.ui.expandedSpells[key]=!state.ui.expandedSpells[key]; renderApp(); return;} if(action==='dec' || action==='inc'){const path=btn.dataset.path; const current=Number(getByPath(state,path) ?? 0); const max=Number(btn.dataset.max || current+999); const next=action==='dec' ? Math.max(0,current-1) : Math.min(max,current+1); setByPath(state,path,next); renderApp(); return;} if(action==='toggle'){const path=btn.dataset.path; setByPath(state,path, !getByPath(state,path)); renderApp(); return;} if(action==='toggleShield'){state.resources.shieldActive=!state.resources.shieldActive; if(state.resources.shieldActive) state.resources.reactionUsed=true; renderApp(); return;} if(action==='toggleItemUse'){const key=btn.dataset.key; state.itemUses[key]=!state.itemUses[key]; renderApp(); return;} if(action==='rollSpirit'){state.lastSpiritRoll=Math.floor(Math.random()*10)+1; renderApp(); return;} if(action==='shortRest'){shortRest(); renderApp(); return;} if(action==='longRest'){longRest(); renderApp(); return;} if(action==='resetAll'){resetAll(); renderApp(); return;}}
function handleChange(event){const el=event.target; const action=el.dataset.action; if(action==='number'){const path=el.dataset.path; let value=Number(el.value || 0); value = path==='hp.max' ? Math.max(1,value) : Math.max(0,value); setByPath(state,path,value); if(path==='hp.max' && state.hp.current>state.hp.max) state.hp.current=state.hp.max; renderApp(); return;} if(action==='checkbox'){setByPath(state, el.dataset.path, !!el.checked); renderApp();}}
function handleInput(event){const el=event.target; if(el.dataset.action==='textarea'){setByPath(state, el.dataset.path, el.value); saveState(); const pill=document.querySelector('.saved-pill'); if(pill) pill.textContent = `Saved locally • ${new Date().toLocaleTimeString([], {hour:'numeric', minute:'2-digit'})}`;}}
document.addEventListener('click', handleClick); document.addEventListener('change', handleChange); document.addEventListener('input', handleInput); renderApp();